const resp = $input.first().json;
const text = resp.content?.[0]?.text || '[]';
let captions = [];
try {
  const match = text.match(/\[.*\]/s);
  if (match) captions = JSON.parse(match[0]);
} catch { captions = [{ caption: text.substring(0, 150), hashtags: '#TotalGuard #MadisonWI' }]; }
return [{ json: { captions, count: captions.length } }];
